[CmdletBinding()]param([Parameter(Mandatory)][string]$ProjectRoot,[switch]$DryRun)
$ErrorActionPreference='Stop';$project=(Resolve-Path -LiteralPath $ProjectRoot).Path;$studio=Join-Path $project '.studio';$changed=[Collections.Generic.List[string]]::new();$types=@{PROJECT_STATE='project-state';ACTIVE_AND_DEFERRED_SCOPE='active-scope';APPROVED_CONCEPT='approved-concept';TECH_DECISION='technical-decision';DESIGN_SYSTEM='design-system';IMPLEMENTATION_PLAN='implementation-plan';ACCEPTANCE_CRITERIA='acceptance-criteria';COPY='copy'}
foreach($entry in $types.GetEnumerator()){$path=Join-Path $studio ($entry.Key+'.md');if(-not(Test-Path $path)){continue};$text=Get-Content -Raw $path;if($text -match '<!--\s*studio-record'){continue};$meta=[ordered]@{schemaVersion=1;recordType=$entry.Value;status='draft';owner='legacy-migration';updatedAt=[DateTime]::UtcNow.ToString('o');applicability=@{productTypes=@();surfaces=@()};sources=@();data=@{migration='legacy-unstructured';reason='Metadata could not be safely derived; populate manually.'}};$new="<!-- studio-record`n$($meta|ConvertTo-Json -Depth 6)`n-->`n$text";$changed.Add($path);if(-not $DryRun){$backup=$path+'.legacy-backup';Copy-Item -LiteralPath $path -Destination $backup -Force;Set-Content -LiteralPath $path -Value $new -Encoding utf8}}
[pscustomobject]@{dryRun=[bool]$DryRun;changed=@($changed);note='Migration preserves bodies, creates backups, and never invents readiness, scope, or approval.'}|ConvertTo-Json -Depth 4
